mapper.select:
select ,b.Name as NEWSRATE_USERIDNAME,c.NAME as NEWSRATE_TOUSERIDNAME,b.SFID from a left join sys_app_user b on a.NEWSRATE_USERID = b.USER_ID left join sys_app_user c on a.NEWSRATE_TOUSERID = c.USER_ID where 1=1
and ( NEWSRATE_USERNAME LIKE CONCAT(CONCAT('%', #{pd.keywords}),'%') or NEWSRATE_CONTENT LIKE CONCAT(CONCAT('%', #{pd.keywords}),'%') or NEWSRATE_MEMO LIKE CONCAT(CONCAT('%', #{pd.keywords}),'%') )
and NEWSRATE_ADDTIME >= #{pd.lastStart}
and NEWSRATE_ADDTIME <= #{pd.lastEnd}
and NEWS_ID = #{pd.NEWS_ID}
and (NEWSRATE_PARENTID = '0' or NEWSRATE_PARENTID is null or NEWSRATE_PARENTID = '')
and (NEWSRATE_ID = #{pd.NEWSRATE_PARENTID} or NEWSRATE_PARENTID = #{pd.NEWSRATE_PARENTID})
and (NEWSRATE_USERID = #{pd.RATEUSER_ID} or NEWSRATE_TOUSERID = #{pd.RATEUSER_ID} or NEWSRATE_ID in ( select DISTINCT NEWSRATE_PARENTID from web_newsrate where NEWSRATE_USERID = #{pd.RATEUSER_ID} or NEWSRATE_TOUSERID = #{pd.RATEUSER_ID}))
order by a.NEWSRATE_ADDTIME
